mapper.select:
SELECT book_info.id, title, cover, description,author_id, user.username as author_name FROM book_info left join user on book_info.author_id=user.id
AND (title LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY updated_at DESC LIMIT #{offset},#{pageSize}

SELECT t.id,t.type_name FROM book_type t
INNER JOIN book_info_book_type bb ON t.id = bb.type_id
WHERE bb.book_id = #{id}

mapper.update:
UPDATE book_info
title = #{title}, cover = #{cover}, description = #{description}, is_finished = #{isFinished}, updated_at = NOW()
WHERE id = #{id}
